.toast-error .toast-icon { color: var(--color-danger); background: var(--color-danger-bg); }
.toast-warning .toast-icon { color: var(--accent-amber); background: rgba(212, 168, 83, 0.1); }
.toast-info .toast-icon { color: #8B5CF6; background: rgba(139, 92, 246, 0.1); }

.toast-message {
    flex: 1;
    line-height: 1.4;
}

.toast-close {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    border-radius: 4px;
    padding: 0;
    transition: color var(--duration-fast, 150ms) ease;
}

.toast-close:hover {
    color: var(--text-primary);
}

