    border-color: rgba(160, 120, 48, 0.2);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
}

[data-theme="dark"] .toast-info,
.dark .toast-info {
    background: rgba(124, 106, 170, 0.12);
    color: #b8a8d4;
    border-color: rgba(124, 106, 170, 0.2);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
}

[data-theme="dark"] .toast-close:hover,
