    background: rgba(255, 255, 255, 0.06);
}

[data-theme="dark"] .toast-success .toast-progress,
.dark .toast-success .toast-progress { background: rgba(163, 201, 168, 0.2); }

[data-theme="dark"] .toast-error .toast-progress,
